```spl
// Sélection temporelle — modifiers
earliest=-1h latest=now     // Dernière heure
earliest=-24h latest=-1h    // Entre -24h et -1h
earliest=-7d                // 7 derniers jours
earliest=01/01/2024:00:00:00 latest=01/31/2024:23:59:59  // Période fixe

// Unités : s=secondes, m=minutes, h=heures, d=jours, w=semaines, mon=mois

// Afficher N résultats
index=main | head 10    // 10 premiers
index=main | tail 5     // 5 derniers

// Champs d'un événement
| fields host, source, sourcetype, _time

// Voir les champs disponibles
| fieldsummary

// Dédoublonner
| dedup host
| dedup 3 host  // Garder 3 occurrences par host
```
